import {
  GoogleAuthProvider,
  signInWithPopup,
  signInWithRedirect,
  getRedirectResult,
  createUserWithEmailAndPassword,
  signInWithEmailAndPassword,
  sendPasswordResetEmail,
  RecaptchaVerifier,
  signInWithPhoneNumber,
  onAuthStateChanged,
  signOut as firebaseSignOut,
} from "firebase/auth";
import { auth } from "./firebase";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:4000";

// Google Sign-In
export async function signInWithGoogle() {
  const provider = new GoogleAuthProvider();
  provider.addScope("profile");
  provider.addScope("email");
  try {
    const result = await signInWithPopup(auth, provider);
    return result.user;
  } catch (popupErr) {
    const code = popupErr?.code ?? "";
    if (
      code === "auth/popup-closed-by-user" ||
      code === "auth/popup-blocked" ||
      code === "auth/cancelled-popup-request"
    ) {
      sessionStorage.setItem("tt_google_redirect", "1");
      await signInWithRedirect(auth, provider);
      throw new Error("Redirecting to Google sign-in…");
    }
    throw popupErr;
  }
}

export async function getGoogleRedirectResult() {
  try {
    const result = await getRedirectResult(auth);
    if (result?.user) {
      sessionStorage.removeItem("tt_google_redirect");
      return result.user;
    }
  } catch (err) {
    sessionStorage.removeItem("tt_google_redirect");
    console.error("Redirect result error:", err);
  }
  return null;
}

// Email/Password
export async function signUpWithEmail(email, password) {
  const result = await createUserWithEmailAndPassword(auth, email, password);
  return result.user;
}

export async function signInWithEmail(email, password) {
  const result = await signInWithEmailAndPassword(auth, email, password);
  return result.user;
}

export async function sendPasswordReset(email) {
  await sendPasswordResetEmail(auth, email);
}

// Phone OTP
export function setupRecaptcha(buttonId) {
  if (window.recaptchaVerifier) {
    window.recaptchaVerifier.clear();
  }
  const verifier = new RecaptchaVerifier(auth, buttonId, {
    size: "invisible",
    callback: () => {},
  });
  window.recaptchaVerifier = verifier;
  return verifier;
}

export async function sendOTP(phoneNumber) {
  const verifier = setupRecaptcha("send-otp-btn");
  return signInWithPhoneNumber(auth, phoneNumber, verifier);
}

export async function verifyOTP(confirmation, otp) {
  const result = await confirmation.confirm(otp);
  return result.user;
}

// Profile management via API
export async function saveUserProfile(user, profile) {
  const idToken = await user.getIdToken();
  const res = await fetch(`${API_BASE}/api/user/profile`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${idToken}`,
    },
    body: JSON.stringify({
      name: profile.name,
      role: profile.role,
      examMode: profile.examMode ?? "JEE",
    }),
  });
  if (!res.ok) {
    const data = await res.json();
    throw new Error(data.error ?? "Failed to save profile");
  }
}

export async function getUserProfile(uid) {
  const user = auth.currentUser;
  if (!user) return null;
  const idToken = await user.getIdToken();
  const res = await fetch(`${API_BASE}/api/user/profile`, {
    headers: { Authorization: `Bearer ${idToken}` },
  });
  if (!res.ok) return null;
  const data = await res.json();
  return data.profile ?? null;
}

export async function signOut() {
  await firebaseSignOut(auth);
}

export function onAuthChange(callback) {
  return onAuthStateChanged(auth, callback);
}

export function getCurrentUser() {
  return auth.currentUser;
}
